using System;
using System.Collections.Generic;
using System.Linq;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Routing;
using QuickCode.Demo.Infrastructure.Integration.Nswag.Clients.IdentityModuleApi.Contracts;
using QuickCode.Demo.Portal.Models;

namespace QuickCode.Demo.Portal.Helpers;

public static class PortalNavigationHelper
{
    public static bool IsActivePath(string? requestPath, string? actionName)
    {
        if (string.IsNullOrWhiteSpace(actionName))
            return false;

        var path = NormalizePath(requestPath);
        var action = NormalizePath(actionName);

        return path.Equals(action, StringComparison.OrdinalIgnoreCase);
    }

    public static bool IsDashboard(string? requestPath)
    {
        var path = NormalizePath(requestPath);
        return path == "/"
               || path.Equals("/Home", StringComparison.OrdinalIgnoreCase)
               || path.Equals("/Home/Index", StringComparison.OrdinalIgnoreCase);
    }

    public static bool IsDashboardPage(HttpContext? httpContext)
    {
        if (httpContext == null)
            return false;

        var controller = httpContext.GetRouteValue("controller")?.ToString();
        var action = httpContext.GetRouteValue("action")?.ToString();
        if (IsHomeIndexRoute(controller, action))
            return true;

        return IsDashboard(httpContext.Request.Path.Value);
    }

    public static IReadOnlyList<PortalBreadcrumbItem> BuildBreadcrumb(
        string? requestPath,
        IReadOnlyList<PortalMenuDto> menuItems,
        string? pageTitleOverride = null)
    {
        if (IsDashboard(requestPath))
            return Array.Empty<PortalBreadcrumbItem>();

        var allMenus = menuItems as List<PortalMenuDto> ?? new List<PortalMenuDto>(menuItems);
        var normalizedPath = NormalizePath(requestPath);
        var items = new List<PortalBreadcrumbItem>
        {
            CreateLinkCrumb("Dashboard", "/", normalizedPath)
        };

        PortalMenuDto? match = null;
        foreach (var menu in allMenus)
        {
            if (IsActivePath(normalizedPath, menu.ActionName))
            {
                match = menu;
                break;
            }
        }

        if (match != null)
        {
            items.AddRange(GetSectionItems(match, allMenus, normalizedPath));
            items.Add(CreateMenuCrumb(match, normalizedPath, isActive: true));
            return items;
        }

        if (!string.IsNullOrWhiteSpace(pageTitleOverride))
        {
            items.Add(new PortalBreadcrumbItem
            {
                Text = pageTitleOverride.Trim(),
                IsActive = true
            });
            return items;
        }

        var fallbackTitle = GetFallbackTitle(normalizedPath);
        if (!string.IsNullOrWhiteSpace(fallbackTitle))
        {
            items.Add(new PortalBreadcrumbItem
            {
                Text = fallbackTitle,
                IsActive = true
            });
        }

        return items;
    }

    public static string FormatMenuItemTitle(PortalMenuDto item)
    {
        if (string.Equals(item.Name, "AuditLogs", StringComparison.OrdinalIgnoreCase))
        {
            return $"{item.ParentName.Replace("Module", "", StringComparison.OrdinalIgnoreCase)} {item.Text}"
                .AsSplitCapitalWithUnderline();
        }

        return item.Text.SplitCamelCaseToString();
    }

    public static string FormatSectionTitle(string parentName)
    {
        if (string.IsNullOrWhiteSpace(parentName))
            return string.Empty;

        if (parentName.EndsWith("Module", StringComparison.OrdinalIgnoreCase))
            return parentName[..^6].SplitCamelCaseToString();

        return parentName.SplitCamelCaseToString();
    }

    private static IEnumerable<PortalBreadcrumbItem> GetSectionItems(
        PortalMenuDto match,
        IReadOnlyList<PortalMenuDto> menuItems,
        string currentPath)
    {
        var parentName = match.ParentName.AsString().Trim();

        if (string.Equals(match.Name, "AuditLogs", StringComparison.OrdinalIgnoreCase))
        {
            var auditMenus = new List<PortalMenuDto>();
            foreach (var menu in menuItems)
            {
                if (string.Equals(menu.Name, "AuditLogs", StringComparison.OrdinalIgnoreCase))
                    auditMenus.Add(menu);
            }

            yield return CreateMenuGroupCrumb(
                "Audit Logs",
                auditMenus,
                currentPath);
            yield break;
        }

        if (parentName.EndsWith("Module", StringComparison.OrdinalIgnoreCase))
        {
            var moduleMenus = new List<PortalMenuDto>();
            foreach (var menu in menuItems)
            {
                if (menu.ParentName.AsString().Trim().EndsWith("Module"))
                    moduleMenus.Add(menu);
            }

            yield return CreateModuleOverviewCrumb(moduleMenus, currentPath);

            var modulePages = new List<PortalMenuDto>();
            foreach (var menu in menuItems)
            {
                if (menu.ParentName.AsString().Trim().Equals(parentName, StringComparison.OrdinalIgnoreCase)
                    && !string.Equals(menu.Name, "AuditLogs", StringComparison.OrdinalIgnoreCase))
                {
                    modulePages.Add(menu);
                }
            }

            yield return CreateMenuGroupCrumb(
                FormatSectionTitle(parentName),
                modulePages,
                currentPath);
            yield break;
        }

        var managementMenus = new List<PortalMenuDto>();
        foreach (var menu in menuItems)
        {
            if (!menu.ParentName.AsString().Trim().EndsWith("Module"))
                managementMenus.Add(menu);
        }

        yield return CreateManagementOverviewCrumb(managementMenus, currentPath);

        var groupPages = new List<PortalMenuDto>();
        foreach (var menu in menuItems)
        {
            if (menu.ParentName.AsString().Trim().Equals(parentName, StringComparison.OrdinalIgnoreCase))
                groupPages.Add(menu);
        }

        yield return CreateMenuGroupCrumb(
            FormatSectionTitle(parentName),
            groupPages,
            currentPath);
    }

    private static PortalBreadcrumbItem CreateLinkCrumb(
        string text,
        string url,
        string currentPath,
        bool isActive = false)
    {
        return new PortalBreadcrumbItem
        {
            Text = text,
            Url = url,
            IsActive = isActive || IsActivePath(currentPath, url)
        };
    }

    private static PortalBreadcrumbItem CreateMenuCrumb(
        PortalMenuDto menu,
        string currentPath,
        bool isActive = false)
    {
        return new PortalBreadcrumbItem
        {
            Text = FormatMenuItemTitle(menu),
            Url = menu.ActionName,
            IsActive = isActive,
            RelatedLinks = BuildMenuLinks(new[] { menu }, currentPath)
        };
    }

    private static PortalBreadcrumbItem CreateMenuGroupCrumb(
        string text,
        IReadOnlyList<PortalMenuDto> groupMenus,
        string currentPath)
    {
        var links = BuildMenuLinks(groupMenus, currentPath);
        return new PortalBreadcrumbItem
        {
            Text = text,
            Url = links.FirstOrDefault(i => !i.IsActive)?.Url ?? links.FirstOrDefault()?.Url,
            RelatedLinks = links
        };
    }

    private static PortalBreadcrumbItem CreateModuleOverviewCrumb(
        IReadOnlyList<PortalMenuDto> moduleMenus,
        string currentPath)
    {
        var moduleLinks = new List<PortalBreadcrumbLink>();
        foreach (var group in moduleMenus
                     .Where(i => !string.Equals(i.Name, "AuditLogs", StringComparison.OrdinalIgnoreCase))
                     .GroupBy(i => i.ParentName.AsString().Trim()))
        {
            PortalMenuDto? firstPage = null;
            foreach (var menu in group.OrderBy(i => FormatMenuItemTitle(i)))
            {
                if (string.IsNullOrWhiteSpace(menu.ActionName))
                    continue;

                firstPage = menu;
                break;
            }

            if (firstPage == null)
                continue;

            moduleLinks.Add(new PortalBreadcrumbLink(
                FormatSectionTitle(group.Key),
                firstPage.ActionName,
                group.Any(i => IsActivePath(currentPath, i.ActionName))));
        }

        moduleLinks.Sort((left, right) => string.Compare(left.Text, right.Text, StringComparison.OrdinalIgnoreCase));

        return new PortalBreadcrumbItem
        {
            Text = "Modules",
            Url = moduleLinks.FirstOrDefault()?.Url,
            RelatedLinks = moduleLinks
        };
    }

    private static PortalBreadcrumbItem CreateManagementOverviewCrumb(
        IReadOnlyList<PortalMenuDto> managementMenus,
        string currentPath)
    {
        var groupLinks = new List<PortalBreadcrumbLink>();
        foreach (var group in managementMenus.GroupBy(i => i.ParentName.AsString().Trim()))
        {
            PortalMenuDto? firstPage = null;
            foreach (var menu in group.OrderBy(i => FormatMenuItemTitle(i)))
            {
                if (string.IsNullOrWhiteSpace(menu.ActionName))
                    continue;

                firstPage = menu;
                break;
            }

            if (firstPage == null)
                continue;

            groupLinks.Add(new PortalBreadcrumbLink(
                FormatSectionTitle(group.Key),
                firstPage.ActionName,
                group.Any(i => IsActivePath(currentPath, i.ActionName))));
        }

        groupLinks.Sort((left, right) => string.Compare(left.Text, right.Text, StringComparison.OrdinalIgnoreCase));

        return new PortalBreadcrumbItem
        {
            Text = "Management",
            Url = groupLinks.FirstOrDefault()?.Url,
            RelatedLinks = groupLinks
        };
    }

    private static IReadOnlyList<PortalBreadcrumbLink> BuildMenuLinks(
        IEnumerable<PortalMenuDto> menus,
        string currentPath)
    {
        var links = new List<PortalBreadcrumbLink>();
        foreach (var menu in menus)
        {
            if (string.IsNullOrWhiteSpace(menu.ActionName))
                continue;

            links.Add(new PortalBreadcrumbLink(
                FormatMenuItemTitle(menu),
                menu.ActionName,
                IsActivePath(currentPath, menu.ActionName)));
        }

        links.Sort((left, right) => string.Compare(left.Text, right.Text, StringComparison.OrdinalIgnoreCase));
        return links;
    }

    private static string? GetFallbackTitle(string normalizedPath)
    {
        if (string.IsNullOrWhiteSpace(normalizedPath) || normalizedPath == "/")
            return null;

        var segments = normalizedPath.Trim('/').Split('/', StringSplitOptions.RemoveEmptyEntries);
        if (segments.Length == 0)
            return null;

        var lastSegment = segments[^1];
        if (lastSegment.Equals("List", StringComparison.OrdinalIgnoreCase) && segments.Length > 1)
            lastSegment = segments[^2];

        return lastSegment.SplitCamelCaseToString();
    }

    private static bool IsHomeIndexRoute(string? controller, string? action)
    {
        if (!string.Equals(controller, "Home", StringComparison.OrdinalIgnoreCase))
            return false;

        return string.IsNullOrWhiteSpace(action)
               || string.Equals(action, "Index", StringComparison.OrdinalIgnoreCase);
    }

    private static string NormalizePath(string? path)
    {
        if (string.IsNullOrWhiteSpace(path))
            return "/";

        var normalized = path.Split('?', '#')[0].Trim();
        if (!normalized.StartsWith('/'))
            normalized = "/" + normalized;

        return normalized.TrimEnd('/');
    }
}
